1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration, type Cell } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - nextGeneration", () => {
6	  it("should return empty array when given empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell due to underpopulation (0 neighbors)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells due to underpopulation (1 neighbor each)", () => {
13	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
14	  });
15	  it("should preserve a 2x2 block still life unchanged", () => {
16	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
17	    const result = nextGeneration(block);
18	    expect(result).toHaveLength(4);
19	    expect(result).toEqual(expect.arrayContaining(block));
20	  });
21	  it("should rotate a horizontal blinker (3 in a row) 90 degrees to vertical", () => {
22	    const horizontal: Cell[] = [[0, 0], [0, 1], [0, 2]];
23	    const expected: Cell[] = [[-1, 1], [0, 1], [1, 1]];
24	    const result = nextGeneration(horizontal);
25	    expect(result).toHaveLength(3);
26	    expect(result).toEqual(expect.arrayContaining(expected));
27	  });
28	  it("should kill a live cell with more than 3 live neighbors due to overpopulation", () => {
29	    const cells: Cell[] = [[0, 0], [1, 0], [-1, 0], [0, 1], [0, -1]];
30	    const result = nextGeneration(cells);
31	    expect(result).toEqual(expect.not.arrayContaining([[0, 0]]));
32	  });
33	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
34	  it.todo("should correctly compute the next generation with negative coordinates");
35	});
