1	// game-of-life.ts
2	
3	export type Cell = [number, number];
4	
5	function isNeighbor(cell: Cell, other: Cell): boolean {
6	  const [x, y] = cell;
7	  const [ox, oy] = other;
8	  if (ox === x && oy === y) return false;
9	  return Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
10	}
11	
12	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
13	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
14	}
15	
16	function survives(cell: Cell, liveCells: Cell[]): boolean {
17	  const neighbors = countLiveNeighbors(cell, liveCells);
18	  return neighbors === 2 || neighbors === 3;
19	}
20	
21	function isLive(cell: Cell, liveCells: Cell[]): boolean {
22	  return liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
23	}
24	
25	function cellKey(cell: Cell): string {
26	  return `${cell[0]},${cell[1]}`;
27	}
28	
29	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
30	  [-1, -1], [-1, 0], [-1, 1],
31	  [0, -1],           [0, 1],
32	  [1, -1],  [1, 0],  [1, 1],
33	];
34	
35	function neighborsOf(cell: Cell): Cell[] {
36	  const [x, y] = cell;
37	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
38	}
39	
40	function uniqueCells(cells: Cell[]): Cell[] {
41	  const unique = new Map<string, Cell>();
42	  cells.forEach((cell) => unique.set(cellKey(cell), cell));
43	  return [...unique.values()];
44	}
45	
46	function deadNeighborsOf(liveCells: Cell[]): Cell[] {
47	  const allNeighbors = liveCells.flatMap(neighborsOf);
48	  const deadNeighbors = allNeighbors.filter((cell) => !isLive(cell, liveCells));
49	  return uniqueCells(deadNeighbors);
50	}
51	
52	function isBorn(cell: Cell, liveCells: Cell[]): boolean {
53	  return countLiveNeighbors(cell, liveCells) === 3;
54	}
55	
56	export function nextGeneration(liveCells: Cell[]): Cell[] {
57	  const survivors = liveCells.filter((cell) => survives(cell, liveCells));
58	  const births = deadNeighborsOf(liveCells).filter((cell) => isBorn(cell, liveCells));
59	  return [...survivors, ...births];
60	}
