it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
  const lShape: Cell[] = [[0, 1], [1, 1], [0, 0]];
  const result = nextGeneration(lShape);
  expect(result).toEqual(expect.arrayContaining<Cell>([[1, 0]]));
});
